          <Icon name={conditionIcon} size={64} />
          <Heading level={1}>{props.temperature}°{props.unit}</Heading>
        </Stack>
        <Row justify="center" gap={32}>
          <Stack align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
            <Text variant="body">{props.humidity}%</Text>
          </Stack>
          <Stack align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind</Text>
            <Text variant="body">{props.windSpeed} km/h</Text>
          </Stack>
