// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
  onSubmit?: (data: Record<string, unknown>) => void; // Action: Submit Survey
}

function useComponent(props: Props) {
  const handleSubmit = useCallback((data: Record<string, unknown>) => {
    props.onSubmit?.(data);
  }, [props.onSubmit]);

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({ name: '', email: '', rating: '', interests: [] as string[], comments: '' });
  const [errors, setErrors] = useState({ name: '', email: '' });
  const totalSteps = 5;

  const validateEmail = (email: string) => /^[\w-\.]+@([\w-]+\.)+[\w-]{2,4}$/.test(email);
  const canNext = useMemo(() => {
    if (step === 1) return formData.name.trim() !== '' && validateEmail(formData.email);
    if (step === 2) return formData.rating !== '';
    return true;
  }, [step, formData]);

  const update = (field: string, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    if (field === 'name') setErrors(e => ({ ...e, name: value ? '' : 'Name is required' }));
    if (field === 'email') setErrors(e => ({ ...e, email: validateEmail(value) ? '' : 'Invalid email' }));
  };

  return { step, setStep, formData, errors, update, canNext, handleSubmit, totalSteps };
}

export default function Component(props: Props) {
  const { step, setStep, formData, errors, update, canNext, handleSubmit, totalSteps } = useComponent(props);

  return (
    <Container maxWidth="sm" padding={24}>
      <Stack gap={16}>
        <Heading level={3}>Step {step} of {totalSteps}</Heading>
        <Progress value={(step / totalSteps) * 100} />
        <Card padding={24} shadow="md">
          <Stack gap={20}>
            {step === 1 && (
              <>
                <FormField label="Name" required error={errors.name}><Input value={formData.name} onChange={(v) => update('name', v)} /></FormField>
                <FormField label="Email" required error={errors.email}><Input value={formData.email} onChange={(v) => update('email', v)} /></FormField>
              </>
            )}
            {step === 2 && (
              <FormField label="How satisfied are you?">
                <RadioGroup value={formData.rating} onChange={(v) => update('rating', v)} options={props.satisfactionLabels.map((l, i) => ({ value: (i + 1).toString(), label: l }))} />
              </FormField>
            )}
            {step === 3 && (
              <FormField label="Interests">
                <Stack gap={8}>
                  {props.featureOptions.map(f => (
                    <Checkbox key={f} label={f} checked={formData.interests.includes(f)} onChange={(c) => update('interests', c ? [...formData.interests, f] : formData.interests.filter(i => i !== f))} />
                  ))}
                </Stack>
              </FormField>
            )}
            {step === 4 && (
              <FormField label="Comments">
                <TextArea value={formData.comments} onChange={(v) => update('comments', v)} maxLength={500} showCount />
              </FormField>
            )}
            {step === 5 && (
              <Stack gap={12}>
                <Heading level={4}>Review your answers</Heading>
                <Text variant="bodySmall">Name: {formData.name}</Text>
                <Text variant="bodySmall">Email: {formData.email}</Text>
                <Text variant="bodySmall">Rating: {formData.rating}</Text>
                <Text variant="bodySmall">Interests: {formData.interests.join(', ') || 'None'}</Text>
                <Text variant="bodySmall">Comments: {formData.comments || 'N/A'}</Text>
              </Stack>
            )}
            <Row justify="between">
              <Button variant="ghost" disabled={step === 1} onClick={() => setStep(s => s - 1)}>Back</Button>
              <Button variant="primary" disabled={!canNext} onClick={() => step < totalSteps ? setStep(s => s + 1) : handleSubmit(formData)}>
                {step === totalSteps ? 'Submit' : 'Next'}
              </Button>
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

export { Props };

