import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: { id: string; title: string; priority: string; assignee: string; column: string; dueDate: string }[]; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
  onTaskUpdate?: (data: Record<string, unknown>) => void; // Action: Task Updated
}

function useComponent(props: Props) {
  const handleTaskUpdate = useCallback((data: Record<string, unknown>) => {
    props.onTaskUpdate?.(data);
  }, [props.onTaskUpdate]);

  const [tasks, setTasks] = useState(props.tasks);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState('medium');

  const addTask = (columnId: string) => {
    const newTask = {
      id: Date.now().toString(),
      title: newTaskTitle,
      priority: newTaskPriority,
      assignee: '??',
      column: columnId,
      dueDate: new Date().toLocaleDateString()
    };
    setTasks([...tasks, newTask]);
    handleTaskUpdate({ action: 'create', task: newTask });
    setAddingTo(null);
    setNewTaskTitle('');
  };

  const moveTask = (taskId: string, columnId: string) => {
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, column: columnId } : t);
    setTasks(updatedTasks);
    handleTaskUpdate({ action: 'move', taskId, column: columnId });
  };

  const completedCount = useMemo(() => tasks.filter(t => t.column === 'done').length, [tasks]);

  return { tasks, moveTask, addingTo, setAddingTo, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority, addTask, completedCount, handleTaskUpdate };
}

export default function Component(props: Props) {
  const { tasks, moveTask, addingTo, setAddingTo, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority, addTask, completedCount, handleTaskUpdate } = useComponent(props);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={16}>
        <Row justify="between" align="center">
          <Heading level={2}>Project Board</Heading>
          <Badge variant="primary">{completedCount} / {tasks.length} tasks completed</Badge>
        </Row>
        <Row align="start" gap={16}>
          {props.columns.map((col, idx) => (
            <Box key={col.id ?? idx} background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={16} borderRadius={8} style={{ minWidth: '300px', flex: '0 0 auto' }}>
              <Stack gap={12}>
                <Heading level={4}>{col.name} ({tasks.filter(t => t.column === col.id).length})</Heading>
                {tasks.filter(t => t.column === col.id).map(task => (
                  <Card key={task.id} padding={12} radius="md" shadow="sm">
                    <Stack gap={8}>
                      <Text variant="bodySmall" style={{ fontWeight: 600 }}>{task.title}</Text>
                      <Row justify="between" align="center">
                        <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'primary'}>{task.priority}</Badge>
                        <Dropdown 
                          trigger={<Button size="xs" variant="ghost" aria-label={`Move task ${task.title}`}>Move</Button>}
                          options={props.columns.filter(c => c.id !== col.id).map(c => ({ value: c.id ?? '', label: c.name ?? '' }))}
                          value={col.id ?? ''}
                          onChange={(val) => moveTask(task.id, val)}
                        />
                      </Row>
                    </Stack>
                  </Card>
                ))}
                {addingTo === col.id ? (
                  <Stack gap={8}>
                    <Input label="Task Title" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="Task title..." />
                    <Select value={newTaskPriority} onChange={setNewTaskPriority} options={[{value: 'low', label: 'Low'}, {value: 'medium', label: 'Medium'}, {value: 'high', label: 'High'}]} label="Priority" />
                    <Button onClick={() => addTask(col.id ?? '')}>Save</Button>
                  </Stack>
                ) : (
                  <Button variant="ghost" aria-label={`Add task to ${col.name}`} onClick={() => setAddingTo(col.id ?? null)}>+ Add Task</Button>
                )}
              </Stack>
            </Box>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

