import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: { atomicNumber: number; symbol: string; name: string; atomicWeight: number; category: string; row: number; col: number }[]; // Full periodic table element data
}

function useComponent(props: Props) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);

  const filtered = useMemo(() => {
    const q = search.toLowerCase();
    return props.elements.filter(
      (el) => el.name.toLowerCase().includes(q) || el.symbol.toLowerCase().includes(q)
    );
  }, [props.elements, search]);

  const categories = useMemo(() => [...new Set(props.elements.map((e) => e.category))], [props.elements]);

  return { search, setSearch, selected, setSelected, filtered, categories };
}

export default function Component(props: Props) {
  const { search, setSearch, selected, setSelected, filtered, categories } = useComponent(props);

  const getCategoryColor = (category: string) => {
    const colors: Record<string, string> = {
      'alkali-metal': 'var(--ggui-color-primary-200, #bae6fd)',
      'alkaline-earth-metal': 'var(--ggui-color-primary-300, #7dd3fc)',
      'transition-metal': 'var(--ggui-color-primary-400, #38bdf8)',
      'post-transition-metal': 'var(--ggui-color-primary-500, #0ea5e9)',
      'metalloid': 'var(--ggui-color-info-200, #a5f3fc)',
      'reactive-nonmetal': 'var(--ggui-color-success-200, #bbf7d0)',
      'noble-gas': 'var(--ggui-color-warning-200, #fde68a)',
      'lanthanide': 'var(--ggui-color-error-200, #fecaca)',
      'actinide': 'var(--ggui-color-error-300, #fda4af)',
    };
    return colors[category] || 'var(--ggui-color-surfaceVariant, #f4f4f5)';
  };

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={24}>
        <Heading level={1}>Periodic Table of Elements</Heading>
        <SearchField value={search} onChange={setSearch} placeholder="Search by name or symbol..." />

        <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 'var(--ggui-spacing-1, 4px)' }}>
          {props.elements.map((el) => {
            const isVisible = filtered.includes(el);
            return (
              <button
                key={el.atomicNumber}
                type="button"
                aria-label={`Element ${el.name} (${el.symbol})`}
                onClick={() => setSelected(el)}
                onKeyDown={(e) => e.key === 'Enter' && setSelected(el)}
                style={{
                  all: 'unset',
                  gridColumn: el.col,
                  gridRow: el.row,
                  opacity: isVisible ? 1 : 0.1,
                  cursor: 'pointer',
                  width: '100%'
                }}
              >
                <Card padding="4px" style={{ backgroundColor: getCategoryColor(el.category), textAlign: 'center' }}>
                  <Text variant="caption" style={{ fontSize: '10px' }}>{el.atomicNumber}</Text>
                  <Heading level={6} style={{ fontSize: '14px' }}>{el.symbol}</Heading>
                </Card>
              </button>
            );
          })}
        </Box>

        <Stack direction="horizontal" wrap gap={8} style={{ marginTop: 'var(--ggui-spacing-4)' }}>
          {categories.map((cat) => (
            <Tag key={cat} style={{ backgroundColor: getCategoryColor(cat) }}>{cat}</Tag>
          ))}
        </Stack>

        {selected && (
          <Card padding={24}>
            <Heading level={3}>{selected.name} ({selected.symbol})</Heading>
            <Stack direction="horizontal" gap={16}>
              <Text>Atomic Number: {selected.atomicNumber}</Text>
              <Text>Atomic Weight: {selected.atomicWeight}</Text>
              <Badge>{selected.category}</Badge>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

