import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id: string; name: string; price: number; currency: string; rating: number; reviewCount: number; stock: number; description: string; specifications: unknown[]; reviews: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
  onAddToCart?: (data: Record<string, unknown>) => void; // Action: Add to Cart
}

function useComponent(props: Props) {
  const handleAddToCart = useCallback((data: Record<string, unknown>) => {
    props.onAddToCart?.(data);
  }, [props.onAddToCart]);

  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const increment = () => setQuantity((q) => Math.min(q + 1, props.product.stock));
  const decrement = () => setQuantity((q) => Math.max(q - 1, 1));

  return {
    quantity,
    activeTab,
    setActiveTab,
    increment,
    decrement,
    handleAddToCart: () => handleAddToCart({ productId: props.product.id, quantity })
  };
}

export default function Component(props: Props) {
  const { quantity, activeTab, setActiveTab, increment, decrement, handleAddToCart } = useComponent(props);
  const { product } = props;

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        <Stack direction="horizontal" gap={32} align="start">
          <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={12} padding={80} style={{ flex: 1, textAlign: 'center' }}>
            <Heading level={2} color="var(--ggui-color-onSurfaceVariant, #52525b)">{product.name}</Heading>
          </Box>
          <Stack gap={16} style={{ flex: 1 }}>
            <Heading level={1}>{product.name}</Heading>
            <Stack direction="horizontal" gap={4}>
              {Array.from({ length: 5 }).map((_, i) => (
                <Icon key={i} name={i < Math.round(product.rating) ? 'star' : 'star'} size={20} color={i < product.rating ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outline, #d4d4d8)'} />
              ))}
              <Text variant="caption">({product.reviewCount} reviews)</Text>
            </Stack>
            <Text variant="bodyLarge">{product.currency}{product.price.toFixed(2)}</Text>
            <Badge variant={product.stock > 0 ? (product.stock < 5 ? 'warning' : 'success') : 'error'}>
              {product.stock > 0 ? (product.stock < 5 ? 'Low Stock' : 'In Stock') : 'Out of Stock'}
            </Badge>
            <Stack direction="horizontal" gap={8} align="center">
              <Button variant="ghost" onClick={decrement} disabled={quantity <= 1}>-</Button>
              <Text>{quantity}</Text>
              <Button variant="ghost" onClick={increment} disabled={quantity >= product.stock}>+</Button>
              <Button variant="primary" onClick={handleAddToCart} disabled={product.stock === 0}>Add to Cart</Button>
            </Stack>
          </Stack>
        </Stack>
        <Tabs 
          activeKey={activeTab} 
          onChange={setActiveTab}
          items={[
            { key: 'description', label: 'Description', content: <Text>{product.description}</Text> },
            { key: 'specs', label: 'Specifications', content: (
              <Table columns={[{ key: 'key', header: 'Attribute' }, { key: 'value', header: 'Value' }]} data={product.specifications as {key: string, value: string}[]} />
            ) },
            { key: 'reviews', label: 'Reviews', content: (
              <Stack gap={16}>
                {(product.reviews as {author: string, rating: number, text: string, date: string}[]).map((r, i) => (
                  <Card key={i} padding={16}>
                    <Text variant="label">{r.author} • {r.date}</Text>
                    <Text variant="bodySmall">{Array.from({length: r.rating}).map(() => '★').join('')}</Text>
                    <Text>{r.text}</Text>
                  </Card>
                ))}
              </Stack>
            ) }
          ]} 
        />
      </Stack>
    </Container>
  );
}

