import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: { sender: string; text: string; timestamp: string }[]; // Array of messages with sender name, text, and ISO timestamp
  onSendMessage?: (data: Record<string, unknown>) => void; // Action: Send Message
}

function useComponent(props: Props) {
  const handleSendMessage = useCallback((data: Record<string, unknown>) => {
    props.onSendMessage?.(data);
  }, [props.onSendMessage]);

  const [inputValue, setInputValue] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [props.messages]);

  const onSend = () => {
    if (!inputValue.trim()) return;
    handleSendMessage({
      text: inputValue,
      timestamp: new Date().toISOString()
    });
    setInputValue('');
  };

  return { inputValue, setInputValue, onSend, messagesEndRef };
}

export default function Component(props: Props) {
  const { inputValue, setInputValue, onSend, messagesEndRef } = useComponent(props);

  return (
    <Stack style={{ height: '500px', border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)', borderRadius: 'var(--ggui-shape-radius-lg, 12px)', overflow: 'hidden' }}>
      <Row align="center" justify="between" style={{ padding: 'var(--ggui-spacing-4, 16px)', borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
        <Heading level={3}>{props.title}</Heading>
        <Badge variant="primary">{props.participantCount} participants</Badge>
      </Row>
      <Box style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4, 16px)' }}>
        <Stack gap={12}>
          {props.messages.map((msg, i) => {
            const isSelf = msg.sender === props.currentUser;
            return (
              <Stack key={i} align={isSelf ? 'end' : 'start'}>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{msg.sender} • {new Date(msg.timestamp).toLocaleTimeString()}</Text>
                <Box style={{ padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-md, 8px)', background: isSelf ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)', color: isSelf ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)' }}>
                  <Text color="inherit">{msg.text}</Text>
                </Box>
              </Stack>
            );
          })}
          <div ref={messagesEndRef} />
        </Stack>
      </Box>
      <Row style={{ padding: 'var(--ggui-spacing-4, 16px)', borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)', gap: '8px' }}>
        <Input label="Message" style={{ flex: 1 }} value={inputValue} onChange={setInputValue} placeholder="Type a message..." onKeyDown={(e: any) => e.key === 'Enter' && onSend()} />
        <Button disabled={!inputValue.trim()} onClick={onSend}>Send</Button>
      </Row>
    </Stack>
  );
}

