// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
  onComplete?: (data: Record<string, unknown>) => void; // Action: Complete Setup
}

function useComponent(props: Props) {
  const handleComplete = useCallback((data: Record<string, unknown>) => {
    props.onComplete?.(data);
  }, [props.onComplete]);

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState(props.initialProfile || {
    name: '', email: '', avatar: props.avatarOptions[0],
    role: props.roleOptions[0], emailNotifications: true, theme: 'light'
  });

  const isValid = useMemo(() => {
    if (step === 1) {
      return formData.name.trim() !== '' && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email);
    }
    if (step === 2) return formData.role !== '';
    return true;
  }, [step, formData]);

  const handleUpdate = (field: string, value: any) => setFormData(prev => ({ ...prev, [field]: value }));

  return { step, setStep, formData, handleUpdate, isValid, handleComplete };
}

export default function Component(props: Props) {
  const { step, setStep, formData, handleUpdate, isValid, handleComplete } = useComponent(props);

  return (
    <Container maxWidth="sm" padding={24}>
      <Stack gap={16}>
        <Heading level={2}>Onboarding - Step {step} of 3</Heading>
        <Progress value={(step / 3) * 100} variant="default" />

        <Card padding={24}>
          {step === 1 && (
            <Stack gap={16}>
              <FormField label="Name" required><Input value={formData.name} onChange={(v: string) => handleUpdate('name', v)} /></FormField>
              <FormField label="Email" required><Input type="email" value={formData.email} onChange={(v: string) => handleUpdate('email', v)} /></FormField>
              <Text variant="label">Select Avatar</Text>
              <Row gap={8}>
                {props.avatarOptions.map(a => (
                  <Button key={a} variant={formData.avatar === a ? 'primary' : 'outline'} size="sm" onPress={() => handleUpdate('avatar', a)}>{a}</Button>
                ))}
              </Row>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={16}>
              <FormField label="Role" required>
                <Select value={formData.role} onChange={(v: string) => handleUpdate('role', v)} options={props.roleOptions.map(r => ({ value: r, label: r }))} />
              </FormField>
              <Toggle label="Enable Email Notifications" checked={formData.emailNotifications} onChange={(v: boolean) => handleUpdate('emailNotifications', v)} />
              <Toggle label="Dark Theme" checked={formData.theme === 'dark'} onChange={(v: boolean) => handleUpdate('theme', v ? 'dark' : 'light')} />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={12}>
              <Heading level={4}>Review</Heading>
              <Text><strong>Name:</strong> {formData.name}</Text>
              <Text><strong>Email:</strong> {formData.email}</Text>
              <Text><strong>Avatar:</strong> {formData.avatar}</Text>
              <Text><strong>Role:</strong> {formData.role}</Text>
              <Text><strong>Notifications:</strong> {formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
              <Text><strong>Theme:</strong> {formData.theme === 'dark' ? 'Dark' : 'Light'}</Text>
            </Stack>
          )}
        </Card>

        <Row justify="between">
          <Button variant="ghost" disabled={step === 1} onPress={() => setStep(s => s - 1)}>Back</Button>
          {step < 3 ? (
            <Button variant="primary" disabled={!isValid} onPress={() => setStep(s => s + 1)}>Next</Button>
          ) : (
            <Button variant="primary" onPress={() => handleComplete(formData)}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
